  ThemeProps, Merge } from "@yamada-ui/react"
import type { UseInputBorderProps } from "../input"
import type { UsePopoverStyleProps, UsePopupAnimationProps } from "../popover"
import type { DatePickerStyle } from "./date-picker.style"
