const defaultRender: DatePickerRender = ({
  count,
  focused,
  index,
  max,
  separator,
  value,
}) => {
  const last = count - 1 === index

  return (
    <span style={{ marginInlineEnd: "var(--gap)" }}>
      {value}
      {((!isNumber(max) || count < max) && focused) || !last ? separator : null}
    </span>
  )
}

